noncompliant.code:
resource "aws_s3_bucket" "bad_example" {
  bucket = "my-bucket"
  # No server-side encryption block
}

compliant.code:
resource "aws_s3_bucket" "good_example" {
  bucket = "my-bucket"
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}
